// ✗ Infinite loop
function Broken() {
  const [count, setCount] = useState(0);

  useEffect(() => {
    setCount(count + 1); // triggers re-render → effect fires → setState → ...
  }); // no dependency array

  return <p>{count}</p>; // browser tab freezes
}

// ✓ Fix A: run once with empty array
useEffect(() => {
  setCount(1);
}, []); // fires only on mount

// ✓ Fix B: derive value in render instead
const doubled = count * 2; // no effect needed

// ✗ Infinite loop — new object reference on every render
function Search({ config }) {
  const options = { headers: { 'X-App': 'my-app' } }; // new ref each render

  useEffect(() => {
    fetch('/api/search', options);
    // eslint: 'options' should be in dep array
  }, [options]); // React sees a new 'options' every render → loop
}

// ✓ Fix A: move stable literal outside the component
const OPTIONS = { headers: { 'X-App': 'my-app' } };

function Search({ config }) {
  useEffect(() => {
    fetch('/api/search', OPTIONS);
  }, []); // OPTIONS is module-level, never changes
}

// ✓ Fix B: useMemo when the object depends on props/state
const options = useMemo(
  () => ({ pageSize: config.pageSize }),
  [config.pageSize]
);
useEffect(() => { fetch('/api/search', options); }, [options]);

// ✗ Infinite loop — new function reference on every render
function Timer({ onTick }) {
  const tick = () => onTick(Date.now()); // new ref each render

  useEffect(() => {
    const id = setInterval(tick, 1000);
    return () => clearInterval(id);
  }, [tick]); // new 'tick' each render → effect re-registers every render
}

// ✓ Fix A: define the function inside the effect (no dep needed)
useEffect(() => {
  const id = setInterval(() => onTick(Date.now()), 1000);
  return () => clearInterval(id);
}, [onTick]); // onTick from props — only re-run if it changes

// ✓ Fix B: stabilise with useCallback
const tick = useCallback(() => onTick(Date.now()), [onTick]);
useEffect(() => {
  const id = setInterval(tick, 1000);
  return () => clearInterval(id);
}, [tick]); // tick is stable as long as onTick is stable

// ✗ Subtle loop — effect reads 'items', sorts, writes back
function SortedList({ rawItems }) {
  const [items, setItems] = useState(rawItems);

  useEffect(() => {
    setItems([...items].sort((a, b) => a.name.localeCompare(b.name)));
  }, [items]); // items changes → effect fires → setItems → items changes → ...
}

// ✓ Fix: compute derived value without state
function SortedList({ rawItems }) {
  const sorted = useMemo(
    () => [...rawItems].sort((a, b) => a.name.localeCompare(b.name)),
    [rawItems]
  );
  return <ul>{sorted.map(i => <li key={i.id}>{i.name}</li>)}</ul>;
}

// ✗ New object on every Provider render
function App() {
  const [user, setUser] = useState(null);
  return (
    <UserContext.Provider value={{ user, setUser }}>
      {/* value is a new object every time App re-renders */}
      <Child />
    </UserContext.Provider>
  );
}

function Child() {
  const ctx = useContext(UserContext);
  useEffect(() => {
    // ctx is a new reference on every App render
    fetchUserData(ctx.user?.id).then(ctx.setUser);
  }, [ctx]); // loops every time App re-renders
}

// ✓ Fix: memoize the context value in the Provider
function App() {
  const [user, setUser] = useState(null);
  const value = useMemo(() => ({ user, setUser }), [user]);
  return (
    <UserContext.Provider value={value}>
      <Child />
    </UserContext.Provider>
  );
}

// ✓ Or: consume only the stable parts of context
function Child() {
  const { user } = useContext(UserContext);
  useEffect(() => { /* ... */ }, [user?.id]); // dep is a primitive
}

