// ✗ Wrong: suppress the warning and exclude the cycling dep
useEffect(() => {
  setItems(transform(items));
  // eslint-disable-next-line react-hooks/exhaustive-deps
}, []); // items excluded to prevent loop — but effect uses stale items!

// After the first render, 'items' changes from outside but the effect
// still sees the initial empty array because it captured it in the closure.

// ✓ Right: restructure so the loop doesn't exist
const transformed = useMemo(() => transform(items), [items]);

function Interval() {
  const [count, setCount] = useState(0);
  const countRef = useRef(count);

  // Keep ref in sync with state on every render
  useEffect(() => {
    countRef.current = count;
  });

  // Interval uses the ref, not the state — no dep on count
  useEffect(() => {
    const id = setInterval(() => {
      console.log('current count:', countRef.current); // always fresh
    }, 1000);
    return () => clearInterval(id);
  }, []); // empty array: interval set up once, never reset

  return (
    <button onClick={() => setCount(c => c + 1)}>Increment</button>
  );
}

function AutoSave({ content }) {
  const [state, dispatch] = useReducer(
    (s, action) => {
      if (action.type === 'SAVE_START') return { ...s, saving: true };
      if (action.type === 'SAVE_OK')   return { ...s, saving: false, lastSaved: action.at };
      if (action.type === 'SAVE_ERR')  return { ...s, saving: false, error: action.msg };
      return s;
    },
    { saving: false, lastSaved: null, error: null }
  );

  useEffect(() => {
    const ctrl = new AbortController();
    dispatch({ type: 'SAVE_START' });

    fetch('/api/save', {
      method: 'POST',
      body: content,
      signal: ctrl.signal,
    })
      .then(() => dispatch({ type: 'SAVE_OK', at: Date.now() }))
      .catch(e => {
        if (e.name !== 'AbortError') dispatch({ type: 'SAVE_ERR', msg: e.message });
      });

    return () => ctrl.abort();
  }, [content]); // only 'content' is a dep; dispatch is stable

  return <p>{state.saving ? 'Saving...' : `Saved at ${state.lastSaved}`}</p>;
}

// ✗ count is a dependency — effect resets the interval on every increment
useEffect(() => {
  const id = setInterval(() => setCount(count + 1), 1000); // closes over count
  return () => clearInterval(id);
}, [count]); // new interval registered every second

// ✓ Functional updater — no need to close over count
useEffect(() => {
  const id = setInterval(() => setCount(c => c + 1), 1000);
  return () => clearInterval(id);
}, []); // interval registered once, increments correctly
